import{_ as l,o as t,c as p,ah as i}from"./chunks/framework.y8uoDitO.js";const f=JSON.parse('{"title":"前言","description":null,"frontmatter":{"title":"前言","description":null,"category":"guide"},"headers":[],"relativePath":"guide/preface.md","filePath":"guide/preface.md"}'),o={name:"guide/preface.md"};function a(r,e,n,s,b,c){return t(),p("div",null,[...e[0]||(e[0]=[i('<h1 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h1><br><br><blockquote><p><span style="font-size:36px;">献给</span> <span style="color:#b8860b;font-size:36px;font-weight:bold;">所有玩家</span></p></blockquote><br><p>对于笔者来说，《巫师3：狂猎》是一款令我<span style="color:#b8860b;font-weight:bold;">相见恨晚</span>的游戏。</p><p>这个2015年面世的游戏，我直到2019年高考后才知道它的存在，一开始是被动听的bgm和杰洛特高辨识度的英语配音以及英姿飒爽的Ciri所吸引。终于在2020年底，我通过攒钱和学习装机知识，自己在大学宿舍配了一台 i5-10400f / 1660ti 的机子，并果断下单了《巫师3》的完全版，从此便一发不可收拾，踏上寻女之旅。</p><p>由于我接触3a游戏的时间不长，起初游玩时并不算顺利，也经历了拿起又放弃；有一天看了B站up关于猎魔人世界观的讲解，才得以逐渐代入游戏，并于2021年4月第一次通关主线，Ciri猎魔人结局。</p><p>在游玩的过程中，我非常享受探索陌生的地点和发现崭新的装备，每次新周目都有不同的体验。在次世代三周目时我发现对形色各异的刀剑很感兴趣，我开始收集全钢剑银剑，并记录在word文档里，也开始录制各种素材存硬盘里。<span style="color:#b8860b;font-weight:bold;">从那刻起，我意识到我也许可以为《巫师3》简中社区做点什么</span>。</p><p>时至今日，我的时长已经达到2080h，总共游玩了五周目。</p><p>它是我心目中最伟大的游戏，<span style="color:#b8860b;font-weight:bold;">没有之一</span>。</p><p>它极大程度上影响并奠基了我对电子游戏的看法。</p><p>笔者开发这个PPT建档图鉴的本意是方便猎魔人们二周目选配喜欢的武器。完全是出于个人爱好，<span style="color:#b8860b;font-weight:bold;">完全免费，不求任何回报，不求点赞，也不求b站投币和小黑盒充电，主打单纯的分享</span>。</p><p>每把剑的PPT建档内容将围绕以下几个部分展开：</p><ol><li>剑的代码和名称</li><li>剑的典故和由来</li><li>剑的外观设计描述</li><li>剑的面板属性分析</li><li>剑在游戏中的获取途径</li><li>剑的镶嵌和搭配建议</li><li>笔者对剑的评价</li><li>各种配图和视频</li><li>其他注意事项</li></ol><p>笔者会尽量标注清楚每把剑的获取方式；部分遗物剑通过完成任务固定获得，而大部分都可以随机开宝箱或以战利品形式获得。</p><p>《巫师3》其实游戏难度很低，除了死而无憾难度被小怪围殴，几乎没有难点。所以到了三周目以后，笔者就不再注意武器的面板属性和强度数值等，只在乎外观。追求属性伤害和击杀效率还是主要以猎魔人流派的双剑为主。当然一周目初次游玩的玩家还是建议不要过多地用代码，毕竟会一定程度上影响游戏体验。</p><p>希望我这付出了一个月时间的工作，能实际帮助到大家，改善大家的游戏体验，<span style="color:#b8860b;font-weight:bold;">哪怕是一点点</span>，我都心满意足了。</p><br><br><p align="right">Mary-Beth Gaskill</p><br><br><br><br> 原文来自PPT版图鉴 ',26)])])}const _=l(o,[["render",a]]);export{f as __pageData,_ as default};
